import{_ as e,o as l,c as a,a2 as i}from"./chunks/framework.BQ1gajhD.js";const c=JSON.parse('{"title":"门票预约指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/tickets.md","filePath":"guide/tickets.md","lastUpdated":1784712887000}'),d={name:"guide/tickets.md"};function n(r,t,s,o,g,h){return l(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="门票预约指南" tabindex="-1">门票预约指南 <a class="header-anchor" href="#门票预约指南" aria-label="Permalink to &quot;门票预约指南&quot;">​</a></h1><blockquote><p>&quot;提前预约，避免白跑一趟。&quot;</p></blockquote><h2 id="必须预约的景点" tabindex="-1">必须预约的景点 <a class="header-anchor" href="#必须预约的景点" aria-label="Permalink to &quot;必须预约的景点&quot;">​</a></h2><p>以下景点必须提前在网上预约，现场不售票：</p><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">预约时间</th><th style="text-align:left;">预约方式</th><th style="text-align:left;">注意事项</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>故宫博物院</strong></td><td style="text-align:center;">提前7天</td><td style="text-align:left;">官网/微信</td><td style="text-align:left;">旺季需抢票，晚8点放票</td></tr><tr><td style="text-align:left;"><strong>国家博物馆</strong></td><td style="text-align:center;">提前1-7天</td><td style="text-align:left;">官网/微信/APP</td><td style="text-align:left;">周一闭馆</td></tr><tr><td style="text-align:left;"><strong>军事博物馆</strong></td><td style="text-align:center;">提前1-5天</td><td style="text-align:left;">官网/微信</td><td style="text-align:left;">周一闭馆</td></tr><tr><td style="text-align:left;"><strong>自然博物馆</strong></td><td style="text-align:center;">提前1-3天</td><td style="text-align:left;">官网/微信</td><td style="text-align:left;">周一闭馆，难约</td></tr><tr><td style="text-align:left;"><strong>科技馆</strong></td><td style="text-align:center;">提前1-3天</td><td style="text-align:left;">官网/微信</td><td style="text-align:left;">周一闭馆</td></tr><tr><td style="text-align:left;"><strong>首都博物馆</strong></td><td style="text-align:center;">提前1-7天</td><td style="text-align:left;">官网/微信</td><td style="text-align:left;">周一闭馆</td></tr><tr><td style="text-align:left;"><strong>八达岭长城</strong></td><td style="text-align:center;">建议提前</td><td style="text-align:left;">官网/微信</td><td style="text-align:left;">旺季限流</td></tr><tr><td style="text-align:left;"><strong>颐和园</strong></td><td style="text-align:center;">建议提前</td><td style="text-align:left;">官网/微信</td><td style="text-align:left;">旺季建议预约</td></tr><tr><td style="text-align:left;"><strong>天坛</strong></td><td style="text-align:center;">建议提前</td><td style="text-align:left;">官网/微信</td><td style="text-align:left;">联票需预约</td></tr><tr><td style="text-align:left;"><strong>圆明园</strong></td><td style="text-align:center;">建议提前</td><td style="text-align:left;">官网/微信</td><td style="text-align:left;">联票需预约</td></tr></tbody></table><h2 id="预约方式" tabindex="-1">预约方式 <a class="header-anchor" href="#预约方式" aria-label="Permalink to &quot;预约方式&quot;">​</a></h2><h3 id="官方网站" tabindex="-1">官方网站 <a class="header-anchor" href="#官方网站" aria-label="Permalink to &quot;官方网站&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:left;">官网</th><th style="text-align:left;">公众号</th></tr></thead><tbody><tr><td style="text-align:left;">故宫</td><td style="text-align:left;">www.dpm.org.cn</td><td style="text-align:left;">故宫博物院</td></tr><tr><td style="text-align:left;">国博</td><td style="text-align:left;">www.chnmuseum.cn</td><td style="text-align:left;">国家博物馆</td></tr><tr><td style="text-align:left;">八达岭长城</td><td style="text-align:left;">www.badaling.cn</td><td style="text-align:left;">八达岭长城</td></tr><tr><td style="text-align:left;">颐和园</td><td style="text-align:left;">www.summerpalace-china.com</td><td style="text-align:left;">颐和园</td></tr><tr><td style="text-align:left;">天坛</td><td style="text-align:left;">www.tiantanpark.com</td><td style="text-align:left;">天坛公园</td></tr><tr><td style="text-align:left;">圆明园</td><td style="text-align:left;">www.yuanmingyuanpark.com</td><td style="text-align:left;">圆明园遗址公园</td></tr><tr><td style="text-align:left;">科技馆</td><td style="text-align:left;">www.cstm.org.cn</td><td style="text-align:left;">中国科学技术馆</td></tr></tbody></table><h3 id="预约步骤" tabindex="-1">预约步骤 <a class="header-anchor" href="#预约步骤" aria-label="Permalink to &quot;预约步骤&quot;">​</a></h3><ol><li>搜索景点官方微信公众号或访问官网</li><li>点击「购票/预约」</li><li>选择日期和时段</li><li>填写身份信息（需身份证）</li><li>支付费用</li><li>保存预约二维码或截图</li></ol><h3 id="常用平台" tabindex="-1">常用平台 <a class="header-anchor" href="#常用平台" aria-label="Permalink to &quot;常用平台&quot;">​</a></h3><ul><li><strong>携程、美团、去哪儿</strong>：可预约部分景点</li><li><strong>北京旅游网</strong>：部分景点可约</li><li><strong>各景点官方渠道</strong>：最可靠</li></ul><h2 id="门票价格" tabindex="-1">门票价格 <a class="header-anchor" href="#门票价格" aria-label="Permalink to &quot;门票价格&quot;">​</a></h2><h3 id="旺季-淡季" tabindex="-1">旺季/淡季 <a class="header-anchor" href="#旺季-淡季" aria-label="Permalink to &quot;旺季/淡季&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">旺季时间</th><th style="text-align:center;">淡季时间</th></tr></thead><tbody><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">4.1-10.31</td><td style="text-align:center;">11.1-3.31</td></tr><tr><td style="text-align:left;">天坛</td><td style="text-align:center;">4.1-10.31</td><td style="text-align:center;">11.1-3.31</td></tr><tr><td style="text-align:left;">颐和园</td><td style="text-align:center;">4.1-10.31</td><td style="text-align:center;">11.1-3.31</td></tr><tr><td style="text-align:left;">八达岭长城</td><td style="text-align:center;">4.1-10.31</td><td style="text-align:center;">11.1-3.31</td></tr><tr><td style="text-align:left;">圆明园</td><td style="text-align:center;">无</td><td style="text-align:center;">无</td></tr></tbody></table><h3 id="门票价格表" tabindex="-1">门票价格表 <a class="header-anchor" href="#门票价格表" aria-label="Permalink to &quot;门票价格表&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">旺季门票</th><th style="text-align:center;">淡季门票</th><th style="text-align:center;">联票</th></tr></thead><tbody><tr><td style="text-align:left;">故宫</td><td style="text-align:center;">60元</td><td style="text-align:center;">40元</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">天坛</td><td style="text-align:center;">15元</td><td style="text-align:center;">10元</td><td style="text-align:center;">28元</td></tr><tr><td style="text-align:left;">颐和园</td><td style="text-align:center;">30元</td><td style="text-align:center;">20元</td><td style="text-align:center;">60元</td></tr><tr><td style="text-align:left;">圆明园</td><td style="text-align:center;">10元</td><td style="text-align:center;">10元</td><td style="text-align:center;">25元</td></tr><tr><td style="text-align:left;">八达岭长城</td><td style="text-align:center;">40元</td><td style="text-align:center;">35元</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">10元</td><td style="text-align:center;">5元</td><td style="text-align:center;">20元</td></tr><tr><td style="text-align:left;">景山公园</td><td style="text-align:center;">2元</td><td style="text-align:center;">2元</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">国博</td><td style="text-align:center;">免费</td><td style="text-align:center;">免费</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">科技馆</td><td style="text-align:center;">30元</td><td style="text-align:center;">30元</td><td style="text-align:center;">-</td></tr><tr><td style="text-align:left;">雍和宫</td><td style="text-align:center;">25元</td><td style="text-align:center;">25元</td><td style="text-align:center;">-</td></tr></tbody></table><h2 id="免票-优惠政策" tabindex="-1">免票/优惠政策 <a class="header-anchor" href="#免票-优惠政策" aria-label="Permalink to &quot;免票/优惠政策&quot;">​</a></h2><h3 id="免票人群" tabindex="-1">免票人群 <a class="header-anchor" href="#免票人群" aria-label="Permalink to &quot;免票人群&quot;">​</a></h3><ul><li>6周岁（含）以下或身高1.2米（含）以下儿童</li><li>60周岁（含）以上老年人（部分景点）</li><li>残疾人</li><li>现役军人</li><li>离休干部</li><li>持北京市老年证的老人（部分景点）</li></ul><h3 id="优惠票" tabindex="-1">优惠票 <a class="header-anchor" href="#优惠票" aria-label="Permalink to &quot;优惠票&quot;">​</a></h3><ul><li>6-18周岁未成年人：半价</li><li>全日制本科及以下学历学生：半价</li><li>60周岁以上老人（部分景点）：半价</li></ul><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><ul><li>需携带有效证件</li><li>优惠票需现场购票（部分景点）</li><li>具体政策以各景点公告为准</li></ul><h2 id="预约技巧" tabindex="-1">预约技巧 <a class="header-anchor" href="#预约技巧" aria-label="Permalink to &quot;预约技巧&quot;">​</a></h2><h3 id="故宫抢票攻略" tabindex="-1">故宫抢票攻略 <a class="header-anchor" href="#故宫抢票攻略" aria-label="Permalink to &quot;故宫抢票攻略&quot;">​</a></h3><ol><li><strong>放票时间</strong>：每晚8点放第7天的票</li><li><strong>提前准备</strong>：提前在官网注册，录入常用联系人</li><li><strong>网络选择</strong>：使用WiFi或5G网络</li><li><strong>多设备</strong>：可多人多设备同时抢</li><li><strong>不放弃</strong>：8点15分左右可能有退票</li><li><strong>淡季出行</strong>：淡季票源充足</li></ol><h3 id="自然博物馆预约" tabindex="-1">自然博物馆预约 <a class="header-anchor" href="#自然博物馆预约" aria-label="Permalink to &quot;自然博物馆预约&quot;">​</a></h3><p>自然博物馆票源紧张，建议：</p><ol><li>提前3天预约</li><li>每天上午11点放票</li><li>工作日票源相对充足</li><li>备选方案：科技馆、古动物馆</li></ol><h3 id="博物馆预约" tabindex="-1">博物馆预约 <a class="header-anchor" href="#博物馆预约" aria-label="Permalink to &quot;博物馆预约&quot;">​</a></h3><p>周一闭馆的博物馆：</p><ul><li>故宫、国博、首博、自然博物馆、科技馆、军事博物馆</li></ul><p>周二至周日开放，建议周二至周四前往，人较少。</p><h2 id="入场须知" tabindex="-1">入场须知 <a class="header-anchor" href="#入场须知" aria-label="Permalink to &quot;入场须知&quot;">​</a></h2><h3 id="必须携带" tabindex="-1">必须携带 <a class="header-anchor" href="#必须携带" aria-label="Permalink to &quot;必须携带&quot;">​</a></h3><ul><li>身份证原件（必须！）</li><li>预约二维码/短信</li><li>优惠证件（学生证、老年证等）</li></ul><h3 id="入场流程" tabindex="-1">入场流程 <a class="header-anchor" href="#入场流程" aria-label="Permalink to &quot;入场流程&quot;">​</a></h3><ol><li>排队等候</li><li>出示身份证和预约信息</li><li>安检（禁止携带违禁品）</li><li>刷身份证入场</li><li>部分景点需二次检票</li></ol><h3 id="注意事项-1" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项-1" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><ol><li><strong>迟到</strong>：一般可入场，但建议按时到达</li><li><strong>退票</strong>：大部分景点可提前退票</li><li><strong>改签</strong>：部分景点支持改签</li><li><strong>年票</strong>：部分景点可购买年票</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-没有预约能进吗" tabindex="-1">Q: 没有预约能进吗？ <a class="header-anchor" href="#q-没有预约能进吗" aria-label="Permalink to &quot;Q: 没有预约能进吗？&quot;">​</a></h3><p>A: 故宫、国博等必须预约的景点不能进，其他景点一般可现场购票。</p><h3 id="q-预约后可以退票吗" tabindex="-1">Q: 预约后可以退票吗？ <a class="header-anchor" href="#q-预约后可以退票吗" aria-label="Permalink to &quot;Q: 预约后可以退票吗？&quot;">​</a></h3><p>A: 大部分景点支持提前退票，具体以各景点规定为准。</p><h3 id="q-可以用护照预约吗" tabindex="-1">Q: 可以用护照预约吗？ <a class="header-anchor" href="#q-可以用护照预约吗" aria-label="Permalink to &quot;Q: 可以用护照预约吗？&quot;">​</a></h3><p>A: 部分景点支持护照预约，但建议用身份证。</p><h3 id="q-小孩需要预约吗" tabindex="-1">Q: 小孩需要预约吗？ <a class="header-anchor" href="#q-小孩需要预约吗" aria-label="Permalink to &quot;Q: 小孩需要预约吗？&quot;">​</a></h3><p>A: 6岁以下一般免票，但部分景点需预约免费票。</p><h3 id="q-预约了上午-下午能进吗" tabindex="-1">Q: 预约了上午，下午能进吗？ <a class="header-anchor" href="#q-预约了上午-下午能进吗" aria-label="Permalink to &quot;Q: 预约了上午，下午能进吗？&quot;">​</a></h3><p>A: 一般不能，需按预约时段入场。</p><hr><p><strong>💡 提示</strong>：提前预约是北京旅游的必修课，务必提前规划！</p>',54)])])}const y=e(d,[["render",n]]);export{c as __pageData,y as default};
